const body = $('Webhook notify').first().json.body || {};
const {
  event = 'issue_created',
  issue_id = '',
  title = '',
  description = '',
  category = '',
  raiser_name = '',
  workshop_label = '',
  priority = '',
  status = '',
  comment_body = '',
  actor_name = '',
  attachments = [],
  channel_id,
  custom_text,
  thread_ts,
} = body;

const APP_BASE = 'https://sabhyasachi.github.io/refurb-helpdesk';
const DEFAULT_CHANNEL = 'C0AUNBH7J77';
const link = issue_id ? `${APP_BASE}/#/issues/${issue_id}` : APP_BASE;

const isImg = (u = '') => /\.(png|jpe?g|gif|webp)(\?|$)/i.test(u);
const shorten = (s, n) => (s && s.length > n ? s.slice(0, n) + '…' : (s || ''));

const prioEmoji = {
  urgent: '🔴', high: '🟠', medium: '🟡', low: '🟢',
}[String(priority).toLowerCase()] || '⚪';

let headerText;
if (event === 'issue_created')             headerText = `🛠️ New issue ${issue_id}`;
else if (event === 'issue_status_changed') headerText = `🔄 ${issue_id} → ${status}`;
else if (event === 'issue_reopened')       headerText = `♻️ ${issue_id} reopened`;
else if (event === 'comment_added')        headerText = `💬 New comment on ${issue_id}`;
else if (event === 'issue_assigned')       headerText = `👤 ${issue_id} assigned`;
else                                       headerText = `📣 ${issue_id || 'Update'}`;

const specLine = [
  raiser_name && `Raised by *${raiser_name}*`,
  workshop_label,
  category,
  priority && `${prioEmoji} *${String(priority).toUpperCase()}*`,
  status && `status: *${status}*`,
].filter(Boolean).join(' · ');

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: shorten(`${headerText}${title ? ' — ' + title : ''}`, 150), emoji: true } });
if (specLine) blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: specLine }] });

if (event === 'comment_added' && comment_body) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*${actor_name || 'Someone'} wrote:*\n> ${shorten(comment_body, 2500).replace(/\n/g, '\n> ')}` } });
  if (title) blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `on: *${title}*` }] });
} else if (description) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Description*\n${shorten(description, 2800)}` } });
}

const imgs  = (attachments || []).filter(a => a && ((a.mime || '').startsWith('image/') || isImg(a && a.url)));
const files = (attachments || []).filter(a => a && !imgs.includes(a));
if (imgs.length) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Evidence* (${(attachments||[]).length} file${(attachments||[]).length>1?'s':''})` } });
  imgs.slice(0, 4).forEach(a => { blocks.push({ type: 'image', image_url: a.url, alt_text: a.name || 'evidence' }); });
}
if (files.length) {
  const list = files.slice(0, 8).map(a => `• <${a.url}|${a.name || 'file'}>`).join('\n');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: (imgs.length ? '' : '*Evidence*\n') + list } });
}

const statusLower = String(status).toLowerCase();
const showClose = event !== 'issue_status_changed' || (statusLower !== 'closed' && statusLower !== 'resolved');
const elements = [];
if (issue_id && showClose) {
  elements.push({
    type: 'button',
    text: { type: 'plain_text', text: 'Mark as closed', emoji: true },
    style: 'primary',
    action_id: 'close_issue',
    value: issue_id,
    confirm: {
      title: { type: 'plain_text', text: 'Close this issue?' },
      text:  { type: 'mrkdwn', text: `Close *${issue_id}* — ${shorten(title, 80)}` },
      confirm: { type: 'plain_text', text: 'Close it' },
      deny:    { type: 'plain_text', text: 'Cancel' },
    },
  });
}
elements.push({ type: 'button', text: { type: 'plain_text', text: 'Open in app', emoji: true }, url: link, action_id: 'open_app' });
blocks.push({ type: 'actions', elements });

const fallback = custom_text || `${headerText} — ${title}`.trim();

return [{ json: {
  channel: channel_id || DEFAULT_CHANNEL,
  text: fallback,
  blocks,
  thread_ts: thread_ts || undefined,
}}];

const body = $('Webhook interact').first().json.body || {};
let payload = body.payload;
if (typeof payload === 'string') {
  try { payload = JSON.parse(payload); } catch (e) { payload = {}; }
}
if (!payload || !payload.actions) return [{ json: { __skip: true } }];

const action = payload.actions[0] || {};
const user = payload.user || {};
const channel = (payload.channel && payload.channel.id) || '';
const message_ts = (payload.message && payload.message.ts) || '';
const response_url = payload.response_url || '';

return [{ json: {
  action_id: action.action_id,
  value: action.value,
  user_id: user.id,
  user_name: user.name || user.username || '',
  channel,
  message_ts,
  response_url,
  original_blocks: (payload.message && payload.message.blocks) || [],
}}];

const ctx = $('Parse payload').first().json;
const issue_id = ctx.value;
const rows = $input.all().map(x => x.json);
const issue = rows.find(r => r.issue_id === issue_id);
if (!issue) return [{ json: { __notFound: true, issue_id } }];
return [{ json: {
  ...issue,
  status: 'closed',
  updated_at: new Date().toISOString(),
}}];

const ctx = $('Parse payload').first().json;
const updated = $json;
const blocks = (ctx.original_blocks || []).filter(b => b.type !== 'actions');
blocks.push({
  type: 'context',
  elements: [{ type: 'mrkdwn', text: `✅ Closed by <@${ctx.user_id}> at ${new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' })}` }],
});
return [{ json: {
  replace_original: true,
  text: `✅ ${updated.issue_id} closed`,
  blocks,
  response_url: ctx.response_url,
}}];
